/* Radar de Prazos — calcular prazos críticos
 * Inspirado em Linear SLA breach escalation:
 * monitorar a cada 2h, escalar quando necessário */

const projetos = $('Buscar Projetos').first().json || [];
const memoria = $('Buscar Memória').first().json || {};
const notificados = memoria.notificacoesEnviadas || {};
const agora = new Date();
const alertas = [];

// SLA por etapa (dias)
const SLA_MAP = {
  'Proposta Comercial': 14, 'Contrato': 7, 'Procuração': 5,
  'Coleta de Documentos': 21, 'Análise dos Documentos': 10,
  'Revisão da Apuração': 15, 'Relatório Final': 7,
  'Aprovação Interna': 3, 'Apresentação ao Cliente': 14,
  'Escrituração EFD': 30,
  'Análise de Elegibilidade': 10, 'Estratégia e Aprovação': 3,
  'Proposta ao Cliente': 14, 'Levantamento Documental': 21,
  'Protocolo da Proposta': 7, 'Assinatura do Termo': 7
};

const projs = Array.isArray(projetos) ? projetos : [];

projs.forEach(p => {
  if (p.status === 'ENCERRADO' || p.status === 'CANCELADO') return;
  const nome = p.clienteNome || p.numeroProjeto || '';
  const notifKey = `${p.id}_${p.etapaAtual}`;
  const ultimaNotif = notificados[notifKey];
  const horas6 = 6 * 60 * 60 * 1000;
  const jaNotificado = ultimaNotif && (agora - new Date(ultimaNotif.dataEnvio)) < horas6;

  // 1. SLA da etapa atual
  const sla = SLA_MAP[p.etapaAtual];
  if (sla && p._stateEnteredAt && p._stateEnteredAt[p.etapaAtual]) {
    const dias = Math.floor((agora - new Date(p._stateEnteredAt[p.etapaAtual])) / 86400000);
    if (dias > sla && !jaNotificado) {
      alertas.push({
        severity: 'CRITICAL', tipo: 'SLA_VENCIDO',
        projetoId: p.id, cliente: nome, etapa: p.etapaAtual,
        diasAtraso: dias - sla, slaDias: sla,
        msg: `SLA VENCIDO — ${nome} está em "${p.etapaAtual}" há ${dias} dias (SLA: ${sla}d, atraso: ${dias-sla}d)`
      });
    } else if (dias > sla * 0.7 && !jaNotificado) {
      alertas.push({
        severity: 'HIGH', tipo: 'SLA_RISCO',
        projetoId: p.id, cliente: nome, etapa: p.etapaAtual,
        diasRestantes: sla - dias, slaDias: sla,
        msg: `SLA em risco — ${nome} em "${p.etapaAtual}" há ${dias}d (SLA: ${sla}d, restam ${sla-dias}d)`
      });
    }
  }

  // 2. Procuração vencendo
  if (p.procuracao && p.procuracao.dataValidade) {
    const diasProc = Math.ceil((new Date(p.procuracao.dataValidade) - agora) / 86400000);
    if (diasProc <= 0) {
      alertas.push({ severity: 'CRITICAL', tipo: 'PROCURACAO_EXPIRADA', projetoId: p.id, cliente: nome, msg: `Procuração de ${nome} EXPIRADA` });
    } else if (diasProc <= 15) {
      alertas.push({ severity: 'HIGH', tipo: 'PROCURACAO_VENCENDO', projetoId: p.id, cliente: nome, diasRestantes: diasProc, msg: `Procuração de ${nome} vence em ${diasProc} dias` });
    }
  }

  // 3. PER sem resposta > 320 dias (alerta preventivo antes de 360)
  if (p.pers && p.pers.length) {
    p.pers.forEach(per => {
      if (per.status === 'EM_ANALISE' && per.dataProtocolo) {
        const diasPER = Math.floor((agora - new Date(per.dataProtocolo)) / 86400000);
        if (diasPER > 360) {
          alertas.push({ severity: 'CRITICAL', tipo: 'PER_360', projetoId: p.id, cliente: nome, perNumero: per.numeroPER, dias: diasPER,
            msg: `PER ${per.numeroPER} de ${nome} sem deferimento há ${diasPER} dias (>360d). SELIC incide (art. 7º-A IN 2055/2021).` });
        } else if (diasPER > 320) {
          alertas.push({ severity: 'HIGH', tipo: 'PER_320', projetoId: p.id, cliente: nome, perNumero: per.numeroPER, dias: diasPER,
            msg: `PER ${per.numeroPER} de ${nome} sem resposta há ${diasPER} dias. Limite de 360 dias se aproxima.` });
        }
      }
    });
  }

  // 4. Parcelas em atraso (Gestão de Passivo) — Portaria PGFN 838/2023
  if (p.tipoProjeto === 'REESTRUTURACAO_DIVIDA' && p.execucaoAcordo && p.execucaoAcordo.pagamentos) {
    const atrasadas = p.execucaoAcordo.pagamentos.filter(pg => pg.status === 'ATRASADO').length;
    if (atrasadas >= 3) {
      alertas.push({ severity: 'CRITICAL', tipo: 'RESCISAO_IMINENTE', projetoId: p.id, cliente: nome, parcelas: atrasadas,
        msg: `RESCISÃO IMINENTE — ${nome}: ${atrasadas} parcelas em atraso. Impugnar em 30 dias (Portaria PGFN 838/2023).` });
    } else if (atrasadas >= 2) {
      alertas.push({ severity: 'HIGH', tipo: 'RESCISAO_RISCO', projetoId: p.id, cliente: nome, parcelas: atrasadas,
        msg: `RISCO DE RESCISÃO — ${nome}: ${atrasadas} parcelas em atraso.` });
    }
  }
});

// Separar por severidade
const criticos = alertas.filter(a => a.severity === 'CRITICAL');
const altos = alertas.filter(a => a.severity === 'HIGH');

return [{ json: { alertas, criticos, altos, total: alertas.length, temCritico: criticos.length > 0, temAlto: altos.length > 0 } }];

